      }).not.toThrow();
    });

    test('should throw error if config is invalid', () => {
      expect(() => {
        new EmailProcessor(
          mockGmailClient as any,
          mockClassificationOrchestrator as any,
          mockPersistence as any,
          {} as ProcessingConfig
        );
      }).toThrow('Invalid configuration');
    });
  });

  describe('Batch Processing', () => {
    test('should process batch of emails successfully', async () => {
      const mockEmails: EmailMessage[] = [
        createMockEmail('msg1', 'Test Subject 1'),
        createMockEmail('msg2', 'Test Subject 2'),
        createMockEmail('msg3', 'Test Subject 3'),
      ];

      const mockClassificationResults: ClassificationResult[] = [
