        mockPersistence as any,
        testConfig
      );

      const result = await processor.processBatch({ maxEmails: 10 });

      expect(result.totalProcessed).toBe(3);
      expect(result.successCount).toBe(2);
      expect(result.errorCount).toBe(1);
      expect(result.errors).toHaveLength(1);
      expect(result.errors[0].emailId).toBe('msg2');
      expect(result.errors[0].error.message).toBe('Classification failed');
    });

    test('should handle persistence errors gracefully', async () => {
      const mockEmails: EmailMessage[] = [createMockEmail('msg1', 'Test Subject 1')];
