/**
 * Classification Engine Integration Orchestrator (T041)
 *
 * Cross-package integration between email-processor and classification-engine.
 * Coordinates classification pipeline execution and result aggregation.
 *
 * Features:
 * - Single and batch email classification
 * - Result aggregation from 9-stage pipeline
 * - Explainability trace handling
 * - Error handling with partial failure support
 * - Performance metrics preservation
 */

import { ClassificationPipeline } from '../../../classification-engine/src/pipeline/classification-pipeline';
import { EmailMessage } from '../../../classification-engine/src/types/email-message';
import {
  ClassificationResult,
  ClassificationErrorResult,
} from '../../../classification-engine/src/pipeline/classification-pipeline';
import { ProcessingConfig } from '../../../classification-engine/src/types/category-configuration';

/**
 * Classification Orchestrator
 *
 * Integrates classification-engine package into email-processor workflows.
 * Provides unified interface for classification operations with proper error handling.
 */
export class ClassificationOrchestrator {
  private readonly pipeline: ClassificationPipeline;
  private readonly config: ProcessingConfig;

  /**
   * Initialize classification orchestrator with configuration
   *
   * @param config - Complete processing configuration for classification pipeline
   * @throws {Error} If configuration validation fails
   */
  constructor(config: ProcessingConfig) {
    // Validate configuration
    this.validateConfig(config);

    this.config = config;

    // Initialize classification pipeline from classification-engine package
    this.pipeline = new ClassificationPipeline(config);
  }

  /**
   * Validate processing configuration
   *
   * @param config - Configuration to validate
   * @throws {Error} If configuration is invalid
   */
  private validateConfig(config: ProcessingConfig): void {
    if (!config) {
      throw new Error('Invalid configuration: config is required');
    }

    if (!config.confidence_thresholds) {
      throw new Error('Invalid configuration: confidence_thresholds is required');
    }

    if (!config.settings) {
      throw new Error('Invalid configuration: settings is required');
    }

    // Validate required nested settings
    if (!config.settings.multi_label_selection) {
      throw new Error('Invalid configuration: settings.multi_label_selection is required');
    }

    if (!config.multi_label_policy) {
      throw new Error('Invalid configuration: multi_label_policy is required');
    }
  }

  /**
   * Classify single email through complete 9-stage pipeline
   *
   * Delegates to ClassificationPipeline from classification-engine package.
   * Preserves complete classification result including explainability traces.
   *
   * @param email - Email message to classify
   * @returns Complete classification result with selected labels and explainability
   * @throws {Error} If classification fails
   */
  async classify(email: EmailMessage): Promise<ClassificationResult> {
    try {
      // Delegate to classification pipeline
      const result = await this.pipeline.classify(email);

      // Return complete result (all explainability preserved)
      return result;
    } catch (error) {
      // Propagate classification errors with context
      throw new Error(
        `Classification failed for email ${email.id}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Classify batch of emails through pipeline
   *
   * Processes multiple emails with error resilience - individual email failures
   * do not stop batch processing. Failed emails return error results.
   *
   * @param emails - Array of email messages to classify
   * @returns Array of classification results or error results
   * @throws {Error} If batch processing fails fatally
   */
  async classifyBatch(emails: EmailMessage[]): Promise<Array<ClassificationResult | ClassificationErrorResult>> {
    try {
      // Delegate to classification pipeline batch processing
      const results = await this.pipeline.classifyBatch(emails);

      // Return complete results (successful + errors)
      return results;
    } catch (error) {
      // Fatal batch processing error
      throw new Error(`Batch classification failed: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Get current configuration
   *
   * @returns Processing configuration used by pipeline
   */
  getConfig(): ProcessingConfig {
    return this.pipeline.getConfig();
  }
}

