/**
 * Classification Orchestrator Tests (T041)
 *
 * TDD Approach: Test cross-package integration, result aggregation, and explainability trace handling
 *
 * Test Categories:
 * 1. Cross-package integration with classification-engine
 * 2. Batch processing coordination
 * 3. Result aggregation from pipeline
 * 4. Explainability trace handling
 * 5. Error handling and partial failures
 */

import { ClassificationOrchestrator } from '../../src/orchestrator/classification-orchestrator';
import { ClassificationPipeline } from '../../../classification-engine/src/pipeline/classification-pipeline';
import { EmailMessage } from '../../../classification-engine/src/types/email-message';
import { ClassificationResult } from '../../../classification-engine/src/types/classification-result';
import { ProcessingConfig } from '../../../classification-engine/src/types/category-configuration';

// Mock the classification pipeline
jest.mock('../../../classification-engine/src/pipeline/classification-pipeline');

describe('ClassificationOrchestrator', () => {
  let mockPipeline: jest.Mocked<ClassificationPipeline>;
  let testConfig: ProcessingConfig;

  beforeEach(() => {
    // Setup mock pipeline
    mockPipeline = {
      classify: jest.fn(),
      classifyBatch: jest.fn(),
      getConfig: jest.fn(),
    } as jest.Mocked<ClassificationPipeline>;

    // Minimal test configuration
    testConfig = {
      version: 1,
      taxonomy_notes: 'Test taxonomy',
      settings: {
        initialization: {
          apply_hard_assertions: true,
          seed_category_scores: true,
        },
        rule_scoring: {
          use_lexical_patterns: true,
          apply_subtype_rules: true,
          bounded_aggregation: true,
        },
        attribute_processing: {
          detect_self_sent: true,
          resolve_domains: true,
          derive_context_flags: true,
        },
        attribute_influence: {
          apply_bonuses: true,
          apply_penalties: true,
          enforce_caps: true,
        },
        disambiguation: {
          pairwise_adjustments: true,
          confidence_gap_threshold: 0.15,
        },
        multi_label_selection: {
          max_labels: 3,
          min_secondary_confidence: 0.6,
          allowed_combinations: ['FINANCIAL.ACTIONABLE'],
        },
        ai_routing: {
          high_confidence_threshold: 0.8,
          ai_required_threshold: 0.4,
          skip_ai_conditions: ['hard_assertion_matched'],
        },
      },
      category_signals: {},
      confidence_thresholds: {
        high_confidence: 0.8,
        medium_confidence: 0.6,
        low_confidence: 0.4,
        ai_classification_required: 0.4,
        manual_review_required: 0.2,
        secondary_label_min_gap: 0.15,
      },
      multi_label_policy: {
        max_top_level_labels: 3,
        min_confidence_for_additional: 0.6,
        min_delta_primary_secondary: 0.15,
        allow_financial_actionable_copresence: true,
      },
      domain_signal_overrides: {},
      domain_signal_resolution: {
        mode: 'runtime_resolved',
        source: 'config/domain-sources.json',
        notes: 'Test domain resolution',
      },
      top_level_categories: {},
      attributes: {
        schema: {},
        detectors: [],
        derived: {},
        attribute_bonus_map: {},
      },
      attribute_relevance: {
        _roles_legend: {
          CORE: 'Core attribute',
          PRIMARY_BOOST: 'Primary boost',
          SECONDARY_BOOST: 'Secondary boost',
          DISAMBIGUATOR: 'Disambiguator',
          FILTER: 'Filter',
          STRUCTURAL: 'Structural',
          DERIVED_LINK: 'Derived link',
          NEUTRAL: 'Neutral',
        },
      },
      ai_prompts: {
        feature_extraction: {
          system_prompt: ['Test system prompt'],
          user_prompt: ['Test user prompt'],
        },
        final_classification: {
          system_prompt: ['Test system prompt'],
          user_prompt: ['Test user prompt'],
        },
      },
      feature_extraction_schema: {
        type: 'object',
        properties: {},
        required: [],
      },
    };

    // Mock ClassificationPipeline constructor to return our mock
    (ClassificationPipeline as jest.MockedClass<typeof ClassificationPipeline>).mockImplementation(() => mockPipeline);
  });

  describe('Constructor and Initialization', () => {
    test('should initialize with valid configuration', () => {
      expect(() => {
        new ClassificationOrchestrator(testConfig);
      }).not.toThrow();
    });

    test('should throw error if config is invalid', () => {
      expect(() => {
        new ClassificationOrchestrator({} as ProcessingConfig);
      }).toThrow('Invalid configuration');
    });

    test('should initialize ClassificationPipeline with config', () => {
      new ClassificationOrchestrator(testConfig);

      expect(ClassificationPipeline).toHaveBeenCalledWith(testConfig);
    });
  });

  describe('Single Email Classification', () => {
    test('should classify single email successfully', async () => {
      const mockEmail = createMockEmail('msg1', 'Test Subject');
      const mockResult = createMockClassificationResult('msg1', 0.85);

      mockPipeline.classify.mockResolvedValue(mockResult);

      const orchestrator = new ClassificationOrchestrator(testConfig);
      const result = await orchestrator.classify(mockEmail);

      expect(result).toEqual(mockResult);
      expect(mockPipeline.classify).toHaveBeenCalledWith(mockEmail);
      expect(mockPipeline.classify).toHaveBeenCalledTimes(1);
    });

    test('should handle classification errors', async () => {
      const mockEmail = createMockEmail('msg1', 'Test Subject');

      mockPipeline.classify.mockRejectedValue(new Error('Classification pipeline failed'));

      const orchestrator = new ClassificationOrchestrator(testConfig);

      await expect(orchestrator.classify(mockEmail)).rejects.toThrow('Classification pipeline failed');
    });

    test('should validate email input', async () => {
      const invalidEmail = { id: 'msg1' } as EmailMessage;

      mockPipeline.classify.mockRejectedValue(new Error('Email validation failed: invalid email structure'));

      const orchestrator = new ClassificationOrchestrator(testConfig);

      await expect(orchestrator.classify(invalidEmail)).rejects.toThrow('Email validation failed');
    });
  });

  describe('Batch Classification', () => {
    test('should classify batch of emails successfully', async () => {
      const mockEmails = [
        createMockEmail('msg1', 'Test Subject 1'),
        createMockEmail('msg2', 'Test Subject 2'),
        createMockEmail('msg3', 'Test Subject 3'),
      ];

      const mockResults = [
        createMockClassificationResult('msg1', 0.85),
        createMockClassificationResult('msg2', 0.9),
        createMockClassificationResult('msg3', 0.75),
      ];

      mockPipeline.classifyBatch.mockResolvedValue(mockResults);

      const orchestrator = new ClassificationOrchestrator(testConfig);
      const results = await orchestrator.classifyBatch(mockEmails);

      expect(results).toEqual(mockResults);
      expect(mockPipeline.classifyBatch).toHaveBeenCalledWith(mockEmails);
      expect(mockPipeline.classifyBatch).toHaveBeenCalledTimes(1);
    });

    test('should handle individual email errors in batch', async () => {
      const mockEmails = [
        createMockEmail('msg1', 'Test Subject 1'),
        createMockEmail('msg2', 'Test Subject 2'),
        createMockEmail('msg3', 'Test Subject 3'),
      ];

      const mockResults = [
        createMockClassificationResult('msg1', 0.85),
        { error: new Error('Classification failed'), emailId: 'msg2', processingDurationMs: 100 },
        createMockClassificationResult('msg3', 0.75),
      ];

      mockPipeline.classifyBatch.mockResolvedValue(mockResults);

      const orchestrator = new ClassificationOrchestrator(testConfig);
      const results = await orchestrator.classifyBatch(mockEmails);

      expect(results).toEqual(mockResults);
      expect(results[1]).toHaveProperty('error');
      expect((results[1] as any).error.message).toBe('Classification failed');
    });

    test('should handle empty email array', async () => {
      mockPipeline.classifyBatch.mockResolvedValue([]);

      const orchestrator = new ClassificationOrchestrator(testConfig);
      const results = await orchestrator.classifyBatch([]);

      expect(results).toEqual([]);
      expect(mockPipeline.classifyBatch).toHaveBeenCalledWith([]);
    });

    test('should propagate batch processing errors', async () => {
      const mockEmails = [createMockEmail('msg1', 'Test Subject')];

      mockPipeline.classifyBatch.mockRejectedValue(new Error('Batch processing failed'));

      const orchestrator = new ClassificationOrchestrator(testConfig);

      await expect(orchestrator.classifyBatch(mockEmails)).rejects.toThrow('Batch processing failed');
    });
  });

  describe('Result Aggregation', () => {
    test('should preserve complete classification results', async () => {
      const mockEmail = createMockEmail('msg1', 'Test Subject');
      const mockResult: ClassificationResult = {
        selectedLabels: [
          {
            category: 'FINANCIAL',
            subtype: 'investment',
            confidence: 0.85,
            isPrimary: true,
            selectionRationale: 'High confidence match',
          },
        ],
        candidateScores: {
          FINANCIAL: {
            score: 0.85,
            confidence: 0.85,
            decision: 'selected',
            selectedSubtypeId: 'investment',
            rationale: 'Strong domain and content indicators',
          },
          SOCIAL: {
            score: 0.35,
            confidence: 0.35,
            decision: 'rejected',
            rationale: 'Low confidence',
          },
        },
        selectionSummary: {
          totalLabels: 1,
          primaryCategory: 'FINANCIAL',
          confidenceRange: [0.85, 0.85],
          selectionMethod: 'rule_based',
          needsAi: false,
          topCategories: [
            { category: 'FINANCIAL', score: 0.85 },
            { category: 'SOCIAL', score: 0.35 },
          ],
        },
        needsAiClassification: false,
        processingDurationMs: 150,
      };

      mockPipeline.classify.mockResolvedValue(mockResult);

      const orchestrator = new ClassificationOrchestrator(testConfig);
      const result = await orchestrator.classify(mockEmail);

      // Verify complete result structure preserved
      expect(result.selectedLabels).toHaveLength(1);
      expect(result.selectedLabels[0]).toHaveProperty('category');
      expect(result.selectedLabels[0]).toHaveProperty('subtype');
      expect(result.selectedLabels[0]).toHaveProperty('confidence');
      expect(result.selectedLabels[0]).toHaveProperty('isPrimary');
      expect(result.selectedLabels[0]).toHaveProperty('selectionRationale');

      expect(result.candidateScores).toHaveProperty('FINANCIAL');
      expect(result.candidateScores).toHaveProperty('SOCIAL');

      expect(result.selectionSummary).toHaveProperty('totalLabels');
      expect(result.selectionSummary).toHaveProperty('primaryCategory');
      expect(result.selectionSummary).toHaveProperty('confidenceRange');
      expect(result.selectionSummary).toHaveProperty('selectionMethod');
      expect(result.selectionSummary).toHaveProperty('needsAi');
      expect(result.selectionSummary).toHaveProperty('topCategories');

      expect(result.needsAiClassification).toBe(false);
      expect(result.processingDurationMs).toBe(150);
    });
  });

  describe('Configuration Management', () => {
    test('should expose configuration via getConfig', () => {
      mockPipeline.getConfig.mockReturnValue(testConfig);

      const orchestrator = new ClassificationOrchestrator(testConfig);
      const config = orchestrator.getConfig();

      expect(config).toEqual(testConfig);
      expect(mockPipeline.getConfig).toHaveBeenCalledTimes(1);
    });
  });

  describe('Performance Tracking', () => {
    test('should preserve processing duration in results', async () => {
      const mockEmail = createMockEmail('msg1', 'Test Subject');
      const mockResult = createMockClassificationResult('msg1', 0.85);
      mockResult.processingDurationMs = 250;

      mockPipeline.classify.mockResolvedValue(mockResult);

      const orchestrator = new ClassificationOrchestrator(testConfig);
      const result = await orchestrator.classify(mockEmail);

      expect(result.processingDurationMs).toBe(250);
    });

    test('should preserve processing duration for batch results', async () => {
      const mockEmails = [createMockEmail('msg1', 'Test Subject 1'), createMockEmail('msg2', 'Test Subject 2')];

      const mockResults = [
        { ...createMockClassificationResult('msg1', 0.85), processingDurationMs: 150 },
        { ...createMockClassificationResult('msg2', 0.9), processingDurationMs: 180 },
      ];

      mockPipeline.classifyBatch.mockResolvedValue(mockResults);

      const orchestrator = new ClassificationOrchestrator(testConfig);
      const results = await orchestrator.classifyBatch(mockEmails);

      expect(results[0].processingDurationMs).toBe(150);
      expect(results[1].processingDurationMs).toBe(180);
    });
  });
});

